void manualPortEditClearsImportedHandoffTarget() {
  final importedFlow = PairingHandoffFlow.fromImport(
    const SetupQrImageImport(
      serverId: 'imported-server',
      profileId: 'imported-profile',
      source: PairingHandoffSource.directAppOpen,
    ),
  );

  final editedFlow = importedFlow.applyManualConnectionEdit(
    PairingHandoffManualEdit.port,
  );
  final outcome = editedFlow.afterConnect(
    const NavivoxChannelState(
      profileContacts: [
        NavivoxProfileContact(
          serverId: 'imported-server',
          profileId: 'imported-profile',
          displayName: 'Imported Profile',
          serverLabel: 'Imported Gateway',
          health: NavivoxProfileHealth.online,
          latestPreview: '',
        ),
      ],
    ),
  );

  _expect(
    editedFlow.source == PairingHandoffSource.manual,
    'manual port edits should clear direct-app-open provenance',
  );
  _expect(
    outcome.profileContactToSelect == null,
    'manual port edits should clear imported profile selection target',
  );
  _expect(
    outcome.navigationIntent is OpenChatsList,
    'manual port edits should navigate to the chats list, not the stale imported thread',
  );
}

